def setup_logging():
    """
    Configures the application logger with file handler, rotation,
    and appropriate file permissions.
    """
    # Ensure log directory exists
    if not os.path.exists(LOG_DIR):
        os.makedirs(LOG_DIR)

    # Get the root logger
    logger = logging.getLogger()
    logger.setLevel(LOG_LEVEL)

    # Create a formatter
    formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')

    # Create a rotating file handler
    # This handler writes logging records, after a certain size is reached,
    # the file is closed and a new file is opened.
    # Old files are kept as backups.
    file_handler = logging.handlers.RotatingFileHandler(
        LOG_FILE_PATH,
        maxBytes=MAX_BYTES,
        backupCount=BACKUP_COUNT,
        encoding='utf-8'
    )
    file_handler.setFormatter(formatter)
    logger.addHandler(file_handler)

    # Apply file permissions if the log file already exists
    # RotatingFileHandler creates the file if it doesn't exist,
    # and then we can set permissions.
    if os.path.exists(LOG_FILE_PATH):
        try:
            os.chmod(LOG_FILE_PATH, LOG_FILE_PERMISSIONS)
        except OSError as e:
            # Log this error to stderr as the file logger might not be fully functional yet
            # or if permissions prevent setting them.
            print(f"ERROR: Could not set permissions on {LOG_FILE_PATH}: {e}", file=os.stderr)

