    logging.info(f"Log files will be stored in: {os.path.abspath(LOG_DIR)}")
    logging.info(f"Main log file: {os.path.abspath(LOG_FILE_PATH)}")
    logging.info(f"Max log file size: {MAX_BYTES / (1024*1024):.1f} MB")
    logging.info(f"Number of backup files: {BACKUP_COUNT}")

